import{_ as i,c as l,o,ag as a}from"./chunks/framework.piE7uVCg.js";const p=JSON.parse('{"title":"Serrure autonome VD08-ZM","description":"","frontmatter":{},"headers":[],"relativePath":"securite/access/serrure_auth.md","filePath":"securite/access/serrure_auth.md"}'),r={name:"securite/access/serrure_auth.md"};function s(t,e,n,u,d,c){return o(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="serrure-autonome-vd08-zm" tabindex="-1"><a href="./readme.html">Serrure autonome VD08-ZM</a> <a class="header-anchor" href="#serrure-autonome-vd08-zm" aria-label="Permalink to &quot;[Serrure autonome VD08-ZM](readme.md)&quot;">​</a></h1><h2 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h2><p>Serrure autonome qui fonctionne avec des piles (4xAA) et qui peut etre alimenté en 12v.</p><h2 id="creation-du-code-master" tabindex="-1">Creation du code master <a class="header-anchor" href="#creation-du-code-master" aria-label="Permalink to &quot;Creation du code master&quot;">​</a></h2><ol><li><code>* + #</code></li><li><code>1</code> puis <code>1</code></li><li>Saisir un code de 6 chiffres</li><li><code>#</code></li><li>Saisir à nouveau un code de 6 chiffres</li><li><code>#</code></li></ol><h2 id="changement-de-langue" tabindex="-1">Changement de langue <a class="header-anchor" href="#changement-de-langue" aria-label="Permalink to &quot;Changement de langue&quot;">​</a></h2><p>Pour modifier la langue des instructions vocales en anglais sur votre serrure connectée VD08-ZM, suivez ces étapes directement sur le clavier :</p><ol><li>Réveillez l’écran en touchant le clavier.</li><li>Appuyez sur <code>*</code> puis sur <code>#</code> pour accéder au menu système.</li><li>Vérifiez vos identifiants d’administrateur (appuyez sur votre empreinte digitale ou saisissez votre code d’accès administrateur suivi de <code>#</code>).</li><li>Appuyez sur <code>3</code> pour accéder aux paramètres système.</li><li>Appuyez sur <code>2</code> pour accéder au menu des paramètres de langue.</li><li>Appuyez sur <code>2</code> (ou suivez les indications vocales) pour sélectionner l’anglais, puis appuyez sur # pour confirmer.</li></ol><h2 id="menus" tabindex="-1">Menus <a class="header-anchor" href="#menus" aria-label="Permalink to &quot;Menus&quot;">​</a></h2><ol><li>Admin setting <ol><li>add admin <ol><li>add admin</li><li>Poser une empreinte 3 fois ou saisir un code de 6 chiffres deux fois (les numéros sont générés en 0 1 2 etc)</li></ol></li><li>delete admin <ol><li>Supprimer un admin</li><li>Supprimer tous les admins</li></ol></li></ol></li><li>User serttings <ol><li>add user <ol><li>Poser une empreinte 3 fois ou saisir un code de 6 chiffres deux fois (les numéros sont générés en 10 11 12 etc)</li></ol></li><li>delete user <ol><li>Supprimer un utilisateur</li><li>Supprimer tous les utilisateurs</li></ol></li></ol></li><li>System Settings <ol><li>time settings <ol><li>année</li><li>mois</li><li>jour</li><li>heure</li><li>minutes</li></ol></li><li>language choice <ol><li>chinois</li><li>anglais</li></ol></li><li>Volume control <ol><li>low</li><li>middle</li><li>hight</li><li>mute</li></ol></li><li>Normaly open mode <ol><li>on</li><li>off</li></ol></li><li>double validation mode <ol><li>activate</li><li>cancel</li></ol></li><li>d <ol><li>on</li><li>off</li></ol></li><li>Open lock request query (code temporaire)</li></ol></li><li>Network Settings <ol><li>on</li><li>off</li></ol></li></ol><h2 id="defauts" tabindex="-1">Défauts <a class="header-anchor" href="#defauts" aria-label="Permalink to &quot;Défauts&quot;">​</a></h2><ul><li>Si le lecteur ne réagit pas avec les batteries vérifier le code des couleurs des fiches</li><li>Changer la langue si c&#39;est en chinois</li></ul>',12)])])}const h=i(r,[["render",s]]);export{p as __pageData,h as default};
